#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    NetworkPacket packet;
    stream >> packet.packet_id >> packet.username;

    stream >> hexi::prefixed(packet.scores);

    std::string_view metadata_view = stream.view();
    packet.metadata = std::string(metadata_view);

    if (stream.size() > stream.total_read()) {
        size_t remaining = stream.size() - stream.total_read();
        stream.skip(remaining);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    std::vector<uint8_t> temp_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor adaptor(temp_buffer);
    hexi::binary_stream stream(adaptor);

    auto packet_id_span = stream.span<uint32_t>(1);
    uint32_t packet_id = packet_id_span[0];

    std::string_view username_view;
    stream >> hexi::prefixed(username_view);

    uint32_t score_count = 0;
    stream >> score_count;
    stream.skip(score_count * sizeof(uint32_t));

    PacketInfo info;
    info.packet_id = packet_id;
    info.username = username_view;

    return info;
}

