    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using read function
    adaptor.read(&packet.packet_id, sizeof(packet.packet_id));

    // Read username using prefixed adaptor
    packet.username = adaptor.read<std::string>(); // Uses prefixed adaptor internally

    // Read score count and use read_container to read scores vector
    uint32_t score_count;
    adaptor.read(&score_count, sizeof(score_count));
    adaptor.read_container(packet.scores, score_count);

    // Read metadata string as null-terminated
    packet.metadata = adaptor.read<std::string>(); // Uses null_terminated adaptor internally

    // Skip any remaining padding bytes
    size_t remaining_bytes = adaptor.size();
    if (remaining_bytes > 0) {
        adaptor.skip(remaining_bytes);
    }

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
