```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

bool write_data_with_check(std::vector<uint8_t>& buffer, uint32_t header, const std::vector<uint32_t>& items) {
    // Create buffer_adaptor for the buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Calculate required space: header (4 bytes) + items (each 4 bytes)
    const size_t required_space = sizeof(header) + items.size() * sizeof(uint32_t);

    // Check available space using buffer_adaptor's size method
    if (adaptor.size() < required_space) {
        return false; // Insufficient space
    }

    // Get write pointer using buffer_adaptor's write_ptr method
    auto* write_ptr = adaptor.write_ptr();

    // Write header using pointer arithmetic
    *reinterpret_cast<uint32_t*>(write_ptr) = header;
    write_ptr += sizeof(uint32_t);

