#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance for a simple type (e.g., int)
    hexi::block_allocator<int, element_count> alloc;

    // Demonstrate allocation operations that internally trigger pop()
    int* ptr1 = alloc.allocate();  // Triggers pop() to get a free block
    int* ptr2 = alloc.allocate();  // Another pop() from free list

    // Demonstrate deallocation operations that internally trigger push()
    alloc.deallocate(ptr1);        // Triggers push() to return block to free list
    alloc.deallocate(ptr2);        // Another push() to free list

    // Demonstrate more complex free list management
    int* ptr3 = alloc.allocate();  // Pop() from free list (now has one block)

    // Deallocate multiple times to show push() behavior
    alloc.deallocate(ptr3);

    // Allocate again to show it comes from free list (no pop() needed)
    int* ptr4 = alloc.allocate();

    // Deallocate to push back to free list
    alloc.deallocate(ptr4);

    // Demonstrate fallback to new when free list is exhausted
    // (This would require allocating more than element_count times)
    /*
    for (size_t i = 0; i < element_count + 2; ++i) {
        int* ptr = alloc.allocate();  // For i < element_count: pop() from free list
                                      // For i >= element_count: uses new (no push/pop)
    }
    */
}
```

