        uint32_t temp_count = static_cast<uint32_t>(temperatures.size());
        for (auto& t : temperatures) {
            float temp_value;
            adaptor.read(temp_value);
            hexi::endian::little_to_native_inplace(temp_value);
            t = temp_value;
        }

        // Read pressure
        double p;
        adaptor.read(p);
        hexi::endian::little_to_native_inplace(p);
        pressure = p;
    }
};

